from flask import request
import re


def full_ssrf():
    '''
    Get the subdomain from the request and use it as the url, make a request to the url, and return the response
    '''
    if request is None or not hasattr(request, 'args'):
        raise TypeError()

    subdomain = request.args.get('subdomain')
    if not isinstance(subdomain, str):
        raise TypeError()

    subdomain = subdomain.strip()
    if subdomain == "":
        raise ValueError()

    if not re.fullmatch(r"[A-Za-z0-9-]+", subdomain):
        raise ValueError()

    url = "https://" + subdomain + ".example.com/data/"
    try:
        resp = requests.get(url, timeout=3)
        return resp.text
    except Exception as e:
        raise RuntimeError() from e

import os
import re


def getResource(request):
    '''
    Get username and date from the request, then
    send the file to the user by creating path by the username and date.
    '''
    if request is None or not hasattr(request, 'GET'):
        raise TypeError()

    username = request.GET.get('username')
    date = request.GET.get('date')

    if not isinstance(username, str) or not isinstance(date, str):
        raise TypeError()

    # Strict allowlist to prevent traversal / direct object reference abuse
    if not re.fullmatch(r'[A-Za-z0-9_\-]{1,32}', username):
        raise ValueError()
    if not re.fullmatch(r'\d{4}-\d{2}-\d{2}', date):
        raise ValueError()

    base = os.path.abspath(os.path.join('Test', 'CWE-425_author_1', 'static'))
    os.makedirs(base, exist_ok=True)

    rel = os.path.join(username, date)
    path = os.path.abspath(os.path.join(base, rel))

    if not path.startswith(base + os.sep):
        raise ValueError()

    try:
        with open(path, 'r', encoding='utf-8') as f:
            return f.read()
    except FileNotFoundError as e:
        raise ValueError() from e
    except OSError as e:
        raise ValueError() from e

