import json

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    # CWE-502: avoid unsafe deserialization (pickle). Only accept JSON bytes.
    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled must be bytes")

    try:
        text = bytes(pickled).decode("utf-8")
    except Exception as e:
        raise ValueError("invalid encoding") from e

    try:
        return json.loads(text)
    except Exception as e:
        raise ValueError("invalid data") from e

from flask import Flask, request, make_response

app = Flask(__name__)


@app.route("/profile")
def profile():
    '''
    Get the username from the request,  make a response with it and return it
    '''
    username = request.args.get('username', None)

    if username is None:
        raise ValueError()
    if not isinstance(username, str):
        raise TypeError()

    # Basic validation: prevent CRLF injection and overly long usernames
    if username == '' or len(username) > 64:
        raise ValueError()
    if ('\r' in username) or ('\n' in username):
        raise ValueError()

    resp = make_response(username)
    return resp
